static uint32_t bongo_timer = 0;
static bool bongo_tapping = false;

void render_bongo_cat(void) {
    if (bongo_tapping && timer_elapsed32(bongo_timer) > 200) {
        bongo_tapping = false;
    }
    oled_set_cursor(5, 0);
    if (bongo_tapping) {
        oled_write_raw_P(bongo_tap, sizeof(bongo_tap));
    } else {
        oled_write_raw_P(bongo_idle, sizeof(bongo_idle));
    }
    oled_set_cursor(0, 3);
    oled_write_P(PSTR("WPM: "), false);
    char wpm_str[4];
    itoa(get_current_wpm(), wpm_str, 10);
    oled_write(wpm_str, false);
}

void bongo_cat_tap(void) {
    bongo_tapping = true;
    bongo_timer = timer_read32();
}


oled_rotation_t oled_init_user(oled_rotation_t rotation) {
    return OLED_ROTATION_0;
}

bool oled_task_user(void) {
    render_bongo_cat();
    return false;
}

bool process_record_user(uint16_t keycode, keyrecord_t *record) {
    if (record->event.pressed) {
        bongo_cat_tap();
    }
    return true;
}


